// Check if AI is paused for this contact's conversation in Supabase
try {
  const phone = $('Extract Data').first().json.phone;
  if (!phone) {
    return [{ json: { ...($input.first().json), aiPaused: false } }];
  }

  const SB_URL = $env.SUPABASE_URL || 'https://poailedbsjhxjbniknqg.supabase.co';
  const SB_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

  if (!SB_KEY) {
    console.log(JSON.stringify({ ts: new Date().toISOString(), checkAiPaused: 'no_key', phone }));
    return [{ json: { ...($input.first().json), aiPaused: false } }];
  }

  const contactRes = await fetch(
    `${SB_URL}/rest/v1/contacts?phone_number=eq.${encodeURIComponent(phone)}&select=id&limit=1`,
    { headers: { 'apikey': SB_KEY, 'Authorization': `Bearer ${SB_KEY}` } }
  );
  const contacts = await contactRes.json();

  if (!contacts || !contacts.length) {
    return [{ json: { ...($input.first().json), aiPaused: false } }];
  }

  const contactId = contacts[0].id;

  const convRes = await fetch(
    `${SB_URL}/rest/v1/conversations?contact_id=eq.${contactId}&select=id,ai_paused&limit=1`,
    { headers: { 'apikey': SB_KEY, 'Authorization': `Bearer ${SB_KEY}` } }
  );
  const convs = await convRes.json();

  if (!convs || !convs.length) {
    return [{ json: { ...($input.first().json), aiPaused: false } }];
  }

  const aiPaused = convs[0].ai_paused === true;
  console.log(JSON.stringify({ ts: new Date().toISOString(), checkAiPaused: aiPaused, phone, contactId, convId: convs[0].id }));

  return [{ json: { ...($input.first().json), aiPaused } }];
} catch (err) {
  console.log(JSON.stringify({ ts: new Date().toISOString(), checkAiPausedError: String(err && err.message ? err.message : err) }));
  return [{ json: { ...($input.first().json), aiPaused: false } }];
}
